    "parameters": {
      "type": "object",
      "properties": {
        "ticket_id": {
          "type": "string",
          "description": "The unique identifier for the ticket."
        },
        "reason": {
          "type": "string",
          "description": "The operational justification for the override (e.g., 'high-ARR churn risk')."
